import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
})
export class DashboardComponent {
  today = '2026-07-10';

  totalBacklog = computed(() =>
    this.seed.accounts().reduce((sum, a) => sum + a.backlogValue, 0),
  );
  ytdRevenue = computed(() =>
    this.seed.accounts().reduce((sum, a) => sum + a.ytdRevenue, 0),
  );
  openQuotes = computed(() =>
    this.seed.quotes().filter((q) => q.status === 'submitted' || q.status === 'draft').length,
  );
  overdueTasks = computed(() =>
    this.seed.tasks().filter((t) => t.bucket === 'overdue').length,
  );

  slippageOrders = computed(() => this.seed.orders().filter((o) => o.slippage));
  protectionAlerts = computed(() => this.seed.designIns().filter((d) => d.protectionAlert));
  atRiskAccounts = computed(() =>
    this.seed.accounts().filter((a) => a.connectionLevel === 'at-risk'),
  );
  slaBreaches = computed(() => this.seed.warrantyClaims().filter((w) => w.slaBreached));

  todaysTasks = computed(() =>
    this.seed.tasks().filter((t) => t.bucket === 'today' || t.bucket === 'overdue'),
  );

  recentEmails = computed(() =>
    [...this.seed.emails()].sort((a, b) => b.receivedAt.localeCompare(a.receivedAt)),
  );

  topAccounts = computed(() => {
    const list = this.seed.accounts().filter((a) => a.backlogValue > 0);
    const max = Math.max(1, ...list.map((a) => a.backlogValue));
    return [...list]
      .sort((a, b) => b.backlogValue - a.backlogValue)
      .map((a) => ({ ...a, pct: Math.round((a.backlogValue / max) * 100) }));
  });

  toneBadge(tone: string): string {
    switch (tone) {
      case 'positive': return 'badge-success';
      case 'concerned': return 'badge-warning';
      case 'urgent': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  priorityBadge(priority: string): string {
    switch (priority) {
      case 'high': return 'badge-danger';
      case 'medium': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
